import { Component, ElementRef, EventEmitter, HostListener, Input, Output, ViewChild } from '@angular/core';
const FOCUSABLE = 'button,[href],input,select,textarea,[tabindex]:not([tabindex="-1"])';
@Component({standalone: true, selector: 'app-screen-dialog', template: `<section *ngIf="open" role="dialog" aria-modal="true" aria-labelledby="screen-title" #panel><h2 id="screen-title">Screen</h2><ng-content /><button type="button" (click)="close.emit()">Close</button></section>`})
export class ScreenDialogComponent {
  @Input() open = false; @Output() close = new EventEmitter<void>(); @ViewChild('panel') panel?: ElementRef<HTMLElement>; private previous?: HTMLElement;
  ngOnChanges() { if (this.open) { this.previous = document.activeElement as HTMLElement; queueMicrotask(() => this.nodes()[0]?.focus()); } else this.previous?.focus(); }
  @HostListener('document:keydown.escape') onEscape() { if (this.open) this.close.emit(); }
  @HostListener('keydown', ['$event']) trap(event: KeyboardEvent) { if (event.key !== 'Tab') return; const nodes = this.nodes(); if (!nodes.length) return; const first = nodes[0], last = nodes[nodes.length - 1]; if (event.shiftKey && document.activeElement === first) { event.preventDefault(); last.focus(); } else if (!event.shiftKey && document.activeElement === last) { event.preventDefault(); first.focus(); } }
  private nodes() { return Array.from(this.panel?.nativeElement.querySelectorAll<HTMLElement>(FOCUSABLE) ?? []); }
}

