import { ChangeDetectionStrategy, Component, computed, signal } from '@angular/core';
import { FormControl, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
@Component({standalone: true, selector: 'app-records-form', imports: [ReactiveFormsModule], changeDetection: ChangeDetectionStrategy.OnPush, template: `
<form [formGroup]="form" (ngSubmit)="submit()" aria-describedby="records-errors">
  <label>Name <input formControlName="name" autocomplete="off" /></label>
  <label>Email <input formControlName="email" type="email" /></label>
  @if (showErrors()) { <p id="records-errors" role="alert">Fix the highlighted fields before saving.</p> }
  <button type="submit" [disabled]="form.invalid || saving()">Save</button>
</form>`})
export class RecordsFormComponent {
  readonly saving = signal(false);
  readonly form = new FormGroup({name: new FormControl('', {nonNullable: true, validators: [Validators.required, Validators.minLength(2)]}), email: new FormControl('', {nonNullable: true, validators: [Validators.required, Validators.email]})});
  readonly showErrors = computed(() => this.form.touched && this.form.invalid);
  submit() { this.form.markAllAsTouched(); if (this.form.invalid) return; this.saving.set(true); queueMicrotask(() => this.saving.set(false)); }
}

